SELECT id, user_id, activity_id, check_time, lon, lat, status FROM t_check_in


        user_id = #{userId}


        AND activity_id = #{activityId}

SELECT c.id, c.activity_id, a.title AS activityTitle, a.start_time, a.end_time, c.check_time, c.status, a.status AS activityStatus, a.longitude, a.latitude FROM t_check_in c LEFT JOIN t_activity a ON c.activity_id = a.id WHERE c.user_id = #{userId}
AND c.status = #{status}
ORDER BY a.start_time DESC
